diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
index 703065280096..1dcaac171400 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
@@ -1135,6 +1135,40 @@ static Value *foldUnsignedUnderflowCheck(ICmpInst *ZeroICmp,
   return nullptr;
 }

+/// Fold (icmp ult (A + B), A) | (icmp ult (A + B), B) -> icmp ult (A + B), A
+/// Both comparisons detect unsigned overflow of the same addition and are equivalent.
+static Value *foldUnsignedOverflowOr(ICmpInst *ICmp0, ICmpInst *ICmp1,
+                                     InstCombiner::BuilderTy &Builder) {
+  ICmpInst::Predicate Pred0, Pred1;
+  Value *CmpOp0, *CmpOp1, *CmpVal0, *CmpVal1;
+
+  // Match both icmps as (icmp PRED X, Y)
+  if (!match(ICmp0, m_ICmp(Pred0, m_Value(CmpOp0), m_Value(CmpVal0))) ||
+      !match(ICmp1, m_ICmp(Pred1, m_Value(CmpOp1), m_Value(CmpVal1))))
+    return nullptr;
+
+  // Both must be ICMP_ULT (unsigned less than)
+  if (Pred0 != ICmpInst::ICMP_ULT || Pred1 != ICmpInst::ICMP_ULT)
+    return nullptr;
+
+  // Both LHS operands must be the same add operation
+  Value *Add0, *Add1;
+  if (!match(CmpOp0, m_c_Add(m_Value(Add0), m_Value(Add1))))
+    return nullptr;
+  if (CmpOp1 != CmpOp0)
+    return nullptr;
+
+  // Check if the comparison values are the two operands of the add
+  // Pattern: (icmp ult (A+B), A) | (icmp ult (A+B), B)
+  if ((CmpVal0 == Add0 && CmpVal1 == Add1) ||
+      (CmpVal0 == Add1 && CmpVal1 == Add0)) {
+    // Both icmps detect unsigned overflow, they are equivalent
+    return ICmp0;
+  }
+
+  return nullptr;
+}
+
 struct IntPart {
   Value *From;
   unsigned StartBit;
@@ -3155,6 +3189,13 @@ Value *InstCombinerImpl::foldAndOrOfICmps(ICmpInst *LHS, ICmpInst *RHS,
       return X;
   }

+  // (icmp ult (A + B), A) | (icmp ult (A + B), B) -> icmp ult (A + B), A
+  // Both comparisons detect unsigned overflow and are equivalent.
+  if (!IsAnd && !IsLogical) {
+    if (Value *X = foldUnsignedOverflowOr(LHS, RHS, Builder))
+      return X;
+  }
+
   if (Value *X = foldEqOfParts(LHS, RHS, IsAnd))
     return X;

